var ErrNotFound = errors.New("store: not found")

// Store defines the interface for session storage backends
type Store interface {
	// Ping checks the connectivity to the store
	Ping(ctx context.Context) error

	// GetSandboxBySessionID retrieves sandbox info by session ID
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error)

	// StoreSandbox stores sandbox info (must use SETNX for the session key)
	StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error

	// UpdateSandbox updates sandbox info (must use SET XX)
	UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error

	// DeleteSandboxBySessionID deletes sandbox info by session ID
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error

	// ListExpiredSandboxes lists sandboxes that have expired before the given time
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error)

	// ListInactiveSandboxes lists sandboxes that have been inactive before the given time
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error)

	// UpdateSessionLastActivity updates the last activity timestamp for a session
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error

	// Close closes the store connection
	Close() error
}

// Key prefixes for Redis/Valkey
const (
	SessionKeyPrefix          = "session:"
	SessionExpiryZSet         = "session:expiry"
	SessionLastActivityZSet   = "session:last_activity"
)

// BuildSessionKey returns the full key for a session
func BuildSessionKey(sessionID string) string {
	return SessionKeyPrefix + sessionID
}

