	"sync"

	"k8s.io/klog/v2"
)

var (
	instance Store
	once     sync.Once
)

// Storage returns the singleton Store instance
func Storage() Store {
	once.Do(func() {
		instance = initStore()
	})
	return instance
}

// initStore initializes the store based on STORE_TYPE environment variable
func initStore() Store {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = "redis"
	}

	klog.Infof("Initializing store with type: %s", storeType)

	switch storeType {
	case "redis":
		store, err := NewRedisStore()
		if err != nil {
			klog.Fatalf("Failed to initialize Redis store: %v", err)
		}
		return store
	case "valkey":
		store, err := NewValkeyStore()
		if err != nil {
			klog.Fatalf("Failed to initialize Valkey store: %v", err)
		}
		return store
	default:
		klog.Fatalf("Unsupported store type: %s (supported: redis, valkey)", storeType)
		return nil
	}
}

