import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

// RedisStore implements the Store interface using Redis
type RedisStore struct {
	client *redis.Client
}

// NewRedisStore creates a new Redis store
func NewRedisStore() (*RedisStore, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("REDIS_ADDR environment variable is required")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if v := os.Getenv("REDIS_PASSWORD_REQUIRED"); v != "" {
		passwordRequired, _ = strconv.ParseBool(strings.ToLower(v))
	}

	if passwordRequired && password == "" {
		return nil, fmt.Errorf("REDIS_PASSWORD is required (set REDIS_PASSWORD_REQUIRED=false to disable)")
	}

	opts := &redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	}

	client := redis.NewClient(opts)

	// Test connection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to Redis: %w", err)
	}

	klog.Infof("Connected to Redis at %s", addr)
	return &RedisStore{client: client}, nil
}

// Ping checks the connectivity to Redis
func (s *RedisStore) Ping(ctx context.Context) error {
	return s.client.Ping(ctx).Err()
}

// GetSandboxBySessionID retrieves sandbox info by session ID
func (s *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := BuildSessionKey(sessionID)
	data, err := s.client.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("failed to get sandbox: %w", err)
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

// StoreSandbox stores sandbox info using SETNX
func (s *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox ExpiresAt is zero")
	}

	key := BuildSessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	pipe := s.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, SessionExpiryZSet, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, SessionLastActivityZSet, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to store sandbox: %w", err)
	}

	return nil
}

// UpdateSandbox updates sandbox info using SET XX
func (s *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}

	key := BuildSessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	// Check if key exists first
	exists, err := s.client.Exists(ctx, key).Result()
	if err != nil {
		return fmt.Errorf("failed to check key existence: %w", err)
	}
	if exists == 0 {
		return fmt.Errorf("key not exists")
	}

	if err := s.client.Set(ctx, key, data, 0).Err(); err != nil {
		return fmt.Errorf("failed to update sandbox: %w", err)
	}

	return nil
}

// DeleteSandboxBySessionID deletes sandbox info
func (s *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := BuildSessionKey(sessionID)

	pipe := s.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, SessionExpiryZSet, sessionID)
	pipe.ZRem(ctx, SessionLastActivityZSet, sessionID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to delete sandbox: %w", err)
	}

	return nil
}

// ListExpiredSandboxes lists sandboxes expired before the given time
func (s *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, SessionExpiryZSet, 0, before.Unix(), limit)
}

// ListInactiveSandboxes lists sandboxes inactive before the given time
func (s *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, SessionLastActivityZSet, 0, before.Unix(), limit)
}

// listSandboxesByZSet lists sandboxes by zset score range
func (s *RedisStore) listSandboxesByZSet(ctx context.Context, zsetKey string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	memberObjs, err := s.client.ZRangeByScoreWithScores(ctx, zsetKey, &redis.ZRangeBy{
		Min:   fmt.Sprintf("%d", min),
		Max:   fmt.Sprintf("%d", max),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to list from zset: %w", err)
	}

	var sandboxes []*types.SandboxInfo
	for _, memberObj := range memberObjs {
		sessionID := memberObj.Member.(string)
		sandbox, err := s.GetSandboxBySessionID(ctx, sessionID)
		if err == ErrNotFound {
			// Orphan ZSET member, skip
			continue
		}
		if err != nil {
			klog.Warningf("Failed to get sandbox %s: %v", sessionID, err)
			continue
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

// UpdateSessionLastActivity updates the last activity timestamp
func (s *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session ID is empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	// Check if session exists
	key := BuildSessionKey(sessionID)
	exists, err := s.client.Exists(ctx, key).Result()
	if err != nil {
		return fmt.Errorf("failed to check key existence: %w", err)
	}
	if exists == 0 {
		return ErrNotFound
	}

	if err := s.client.ZAdd(ctx, SessionLastActivityZSet, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err(); err != nil {
		return fmt.Errorf("failed to update last activity: %w", err)
	}

	return nil
}

// Close closes the Redis connection
func (s *RedisStore) Close() error {
	return s.client.Close()
}

