// ValkeyStore implements the Store interface using Valkey
type ValkeyStore struct {
	client valkey.Client
}

// NewValkeyStore creates a new Valkey store
func NewValkeyStore() (*ValkeyStore, error) {
	addrs := os.Getenv("VALKEY_ADDR")
	if addrs == "" {
		return nil, fmt.Errorf("VALKEY_ADDR environment variable is required")
	}

	addresses := strings.Split(addrs, ",")

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if v := os.Getenv("VALKEY_PASSWORD_REQUIRED"); v != "" {
		passwordRequired, _ = strconv.ParseBool(strings.ToLower(v))
	}

	if passwordRequired && password == "" {
		return nil, fmt.Errorf("VALKEY_PASSWORD is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	opts := valkey.ClientOption{
		InitAddress: addresses,
		Password:    password,
	}

	// Optional flags
	if v := os.Getenv("VALKEY_DISABLE_CACHE"); v != "" {
		disableCache, _ := strconv.ParseBool(v)
		opts.DisableCache = disableCache
	}

	if v := os.Getenv("VALKEY_FORCE_SINGLE"); v != "" {
		forceSingle, _ := strconv.ParseBool(v)
		opts.ForceSingleClient = forceSingle
	}

	client, err := valkey.NewClient(opts)
	if err != nil {
		return nil, fmt.Errorf("failed to create Valkey client: %w", err)
	}

	// Test connection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := client.Do(ctx, client.B().Ping().Build()).Error(); err != nil {
		return nil, fmt.Errorf("failed to connect to Valkey: %w", err)
	}

	klog.Infof("Connected to Valkey at %s", addrs)
	return &ValkeyStore{client: client}, nil
}

// Ping checks the connectivity to Valkey
func (s *ValkeyStore) Ping(ctx context.Context) error {
	return s.client.Do(ctx, s.client.B().Ping().Build()).Error()
}

// GetSandboxBySessionID retrieves sandbox info by session ID
func (s *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := BuildSessionKey(sessionID)
	result := s.client.Do(ctx, s.client.B().Get().Key(key).Build())

	if result.IsValkeyNil() {
		return nil, ErrNotFound
	}

	data, err := result.ToString()
	if err != nil {
		return nil, fmt.Errorf("failed to get sandbox: %w", err)
	}

	if data == "" {
		return nil, ErrNotFound
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

// StoreSandbox stores sandbox info
func (s *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox ExpiresAt is zero")
	}

	key := BuildSessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	// Use MULTI for atomic operations
	err = s.client.Do(ctx, s.client.B().Multi().Build()).Error()
	if err != nil {
		return fmt.Errorf("failed to start transaction: %w", err)
	}

	// SETNX - only set if not exists
	s.client.Do(ctx, s.client.B().Set().Key(key).Value(string(data)).Nx().Build())

	// ZADD expiry
	s.client.Do(ctx, s.client.B().Zadd().Key(SessionExpiryZSet).ScoreMember().ScoreMember(
		float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID,
	).Build())

	// ZADD last activity
	s.client.Do(ctx, s.client.B().Zadd().Key(SessionLastActivityZSet).ScoreMember().ScoreMember(
		float64(time.Now().Unix()), sandbox.SessionID,
	).Build())

	// EXEC
	err = s.client.Do(ctx, s.client.B().Exec().Build()).Error()
	if err != nil {
		return fmt.Errorf("failed to store sandbox: %w", err)
	}

	return nil
}

// UpdateSandbox updates sandbox info
func (s *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}

	key := BuildSessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	// Check if key exists first
	existsResult := s.client.Do(ctx, s.client.B().Exists().Key(key).Build())
	exists, err := existsResult.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to check key existence: %w", err)
	}
	if exists == 0 {
		return fmt.Errorf("key not exists")
	}

	// Set XX - only set if exists
	result := s.client.Do(ctx, s.client.B().Set().Key(key).Value(string(data)).Xx().Build())
	if result.IsValkeyNil() {
		return fmt.Errorf("key not exists")
	}
	if err := result.Error(); err != nil {
		return fmt.Errorf("failed to update sandbox: %w", err)
	}

	return nil
}

// DeleteSandboxBySessionID deletes sandbox info
func (s *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := BuildSessionKey(sessionID)

	// Use MULTI for atomic operations
	err := s.client.Do(ctx, s.client.B().Multi().Build()).Error()
	if err != nil {
		return fmt.Errorf("failed to start transaction: %w", err)
	}

	s.client.Do(ctx, s.client.B().Del().Key(key).Build())
	s.client.Do(ctx, s.client.B().Zrem().Key(SessionExpiryZSet).Member(sessionID).Build())
	s.client.Do(ctx, s.client.B().Zrem().Key(SessionLastActivityZSet).Member(sessionID).Build())

	err = s.client.Do(ctx, s.client.B().Exec().Build()).Error()
	if err != nil {
		return fmt.Errorf("failed to delete sandbox: %w", err)
	}

	return nil
}

// ListExpiredSandboxes lists sandboxes expired before the given time
func (s *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, SessionExpiryZSet, 0, before.Unix(), limit)
}

// ListInactiveSandboxes lists sandboxes inactive before the given time
func (s *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, SessionLastActivityZSet, 0, before.Unix(), limit)
}

// listSandboxesByZSet lists sandboxes by zset score range
func (s *ValkeyStore) listSandboxesByZSet(ctx context.Context, zsetKey string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	result := s.client.Do(ctx, s.client.B().Zrangebyscore().Key(zsetKey).Min(fmt.Sprintf("%d", min)).Max(fmt.Sprintf("%d", max)).Limit(0, limit).Build())

	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to list from zset: %w", err)
	}

	var sandboxes []*types.SandboxInfo
	for _, sessionID := range sessionIDs {
		sandbox, err := s.GetSandboxBySessionID(ctx, sessionID)
		if err == ErrNotFound {
			// Orphan ZSET member, skip
			continue
		}
		if err != nil {
			klog.Warningf("Failed to get sandbox %s: %v", sessionID, err)
			continue
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

// UpdateSessionLastActivity updates the last activity timestamp
func (s *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session ID is empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	// Check if session exists
	key := BuildSessionKey(sessionID)
	existsResult := s.client.Do(ctx, s.client.B().Exists().Key(key).Build())
	exists, err := existsResult.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to check key existence: %w", err)
	}
	if exists == 0 {
		return ErrNotFound
	}

	if err := s.client.Do(ctx, s.client.B().Zadd().Key(SessionLastActivityZSet).ScoreMember().ScoreMember(
		float64(at.Unix()), sessionID,
	).Build()).Error(); err != nil {
		return fmt.Errorf("failed to update last activity: %w", err)
	}

	return nil
}

// Close closes the Valkey connection
func (s *ValkeyStore) Close() error {
	s.client.Close()
	return nil
}

