// ServerConfig holds server configuration
type ServerConfig struct {
	Port       int
	EnableTLS  bool
	TLSCert    string
	TLSKey     string
	EnableAuth bool
}

// Server is the workload manager HTTP server
type Server struct {
	config       ServerConfig
	engine       *gin.Engine
	httpServer   *http.Server
	k8sClient    *K8sClient
	informers    *Informers
	tokenCache   *TokenCache
	store        store.Store
	wg           sync.WaitGroup
	ctx          context.Context
	cancel       context.CancelFunc
}

// NewServer creates a new workload manager server
func NewServer(config ServerConfig) (*Server, error) {
	ctx, cancel := context.WithCancel(context.Background())

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	server := &Server{
		config: config,
		engine: engine,
		ctx:    ctx,
		cancel: cancel,
		store:  store.Storage(),
	}

	return server, nil
}

// Start starts the server
func (s *Server) Start() error {
	// Ping store before starting
	ctx, cancel := context.WithTimeout(s.ctx, 5*time.Second)
	defer cancel()
	if err := s.store.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %w", err)
	}
	klog.Info("Store ping successful")

	// Initialize Kubernetes client
	k8sClient, err := NewK8sClient(s.config.EnableAuth)
	if err != nil {
		return fmt.Errorf("failed to create k8s client: %w", err)
	}
	s.k8sClient = k8sClient

	// Initialize informers
	informers, err := NewInformers(k8sClient.GetConfig())
	if err != nil {
		return fmt.Errorf("failed to create informers: %w", err)
	}
	s.informers = informers

	// Wait for informers to sync
	ctxSync, cancelSync := context.WithTimeout(s.ctx, time.Minute)
	defer cancelSync()
	if err := informers.WaitForSync(ctxSync); err != nil {
		return fmt.Errorf("failed to sync informers: %w", err)
	}
	klog.Info("Informers synced")

	// Initialize token cache
	s.tokenCache = NewTokenCache(1000, 5*time.Minute)

	// Setup routes
	s.setupRoutes()

	// Start garbage collector
	s.wg.Add(1)
	go s.runGarbageCollector()

	// Setup HTTP server with h2c
	h2s := &http2.Server{}
	s.httpServer = &http.Server{
		Addr:         fmt.Sprintf(":%d", s.config.Port),
		Handler:      h2c.NewHandler(s.engine, h2s),
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	// Handle shutdown gracefully
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)

	// Start server in goroutine
	go func() {
		klog.Infof("Starting workload manager server on :%d", s.config.Port)
		var err error
		if s.config.EnableTLS {
			if s.config.TLSCert == "" || s.config.TLSKey == "" {
				klog.Fatal("TLS enabled but cert/key not provided")
				return
			}
			err = s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
		} else {
			err = s.httpServer.ListenAndServe()
		}
		if err != nil && err != http.ErrServerClosed {
			klog.Errorf("Server error: %v", err)
		}
	}()

	// Wait for shutdown signal
	<-quit
	klog.Info("Shutting down server...")

	// Shutdown with timeout
	shutdownCtx, shutdownCancel := context.WithTimeout(s.ctx, 15*time.Second)
	defer shutdownCancel()

	s.cancel()

	if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
	}

	// Wait for background workers
	s.wg.Wait()

	// Close store
	s.store.Close()

	klog.Info("Server stopped")
	return nil
}

// setupRoutes configures HTTP routes
func (s *Server) setupRoutes() {
	// Health endpoint (no auth)
	s.engine.GET("/health", s.handleHealth)

	// API v1 group
	v1 := s.engine.Group("/v1")
	v1.Use(s.loggingMiddleware())
	if s.config.EnableAuth {
		v1.Use(s.authMiddleware())
	}

	// AgentRuntime routes
	v1.POST("/agent-runtime", s.handleCreateAgentRuntime)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteAgentRuntime)

	// CodeInterpreter routes
	v1.POST("/code-interpreter", s.handleCreateCodeInterpreter)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteCodeInterpreter)
}

// handleHealth handles health checks
func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

// loggingMiddleware returns a logging middleware
func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return gin.LoggerWithConfig(gin.LoggerConfig{
		Output: os.Stdout,
		Formatter: func(param gin.LogFormatterParams) string {
			return fmt.Sprintf("%s - [%s] \"%s %s %s %d %s \"%s\" %s\"\n",
				param.ClientIP,
				param.TimeStamp.Format(time.RFC1123),
				param.Method,
				param.Path,
				param.Request.Proto,
				param.StatusCode,
				param.Latency,
				param.Request.UserAgent(),
				param.ErrorMessage,
			)
		},
	})
}

// runGarbageCollector runs the garbage collection loop
func (s *Server) runGarbageCollector() {
	defer s.wg.Done()

	ticker := time.NewTicker(types.GCTickInterval)
	defer ticker.Stop()

	for {
		select {
		case <-s.ctx.Done():
			return
		case <-ticker.C:
			s.gcTick()
		}
	}
}

// gcTick performs one garbage collection tick
func (s *Server) gcTick() {
	ctx, cancel := context.WithTimeout(s.ctx, types.GCContextTimeout)
	defer cancel()

	now := time.Now()

	// Query inactive sandboxes (idle timeout)
	inactiveCutoff := now.Add(-types.DefaultSandboxIdleTimeout)
	inactiveSandboxes, err := s.store.ListInactiveSandboxes(ctx, inactiveCutoff, 16)
	if err != nil {
		klog.Warningf("Failed to list inactive sandboxes: %v", err)
	}

	// Query expired sandboxes
	expiredSandboxes, err := s.store.ListExpiredSandboxes(ctx, now, 16)
	if err != nil {
		klog.Warningf("Failed to list expired sandboxes: %v", err)
	}

	// Merge and deduplicate
	sessionIDs := make(map[string]*types.SandboxInfo)
	for _, sb := range inactiveSandboxes {
		sessionIDs[sb.SessionID] = sb
	}
	for _, sb := range expiredSandboxes {
		sessionIDs[sb.SessionID] = sb
	}

	// Delete each unique sandbox
	for sessionID, sandbox := range sessionIDs {
		s.deleteSandbox(ctx, sessionID, sandbox.Kind)
	}
}

// deleteSandbox deletes a sandbox and removes from store
func (s *Server) deleteSandbox(ctx context.Context, sessionID, kind string) {
	klog.Infof("Deleting sandbox: sessionID=%s, kind=%s", sessionID, kind)

	// Delete from K8s
	if err := s.k8sClient.DeleteSandbox(ctx, sessionID, kind); err != nil {
		klog.Warningf("Failed to delete sandbox %s: %v", sessionID, err)
		return
	}

	// Delete from store
	if err := s.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.Warningf("Failed to delete session %s from store: %v", sessionID, err)
	}
}
